import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void typicalCase() {
        // Uber=3, Target=2, Starbucks=1 => top-2: [Uber, Target]
        String[] merchants = {"Uber","Uber","Target","Uber","Target","Starbucks"};
        assertEquals(List.of("Uber","Target"), new Solution().topMerchantsByCount(merchants, 2));
    }

    @Test
    void tiebreakByNameAscending() {
        // A=2, B=2, C=2; tiebreak lex asc => [A,B,C]; top-2: [A,B]
        String[] merchants = {"A","B","A","B","C","C"};
        assertEquals(List.of("A","B"), new Solution().topMerchantsByCount(merchants, 2));
    }

    @Test
    void kEqualsDistinctCount() {
        // k=3 equals number of distinct merchants => return all three in order
        // Amazon=3, Walmart=2, Target=1 => [Amazon,Walmart,Target]
        String[] merchants = {"Amazon","Amazon","Amazon","Walmart","Walmart","Target"};
        assertEquals(List.of("Amazon","Walmart","Target"), new Solution().topMerchantsByCount(merchants, 3));
    }

    @Test
    void kExceedsDistinctCount() {
        // k=5 but only 2 distinct merchants => return both
        String[] merchants = {"PayPal","Stripe"};
        assertEquals(List.of("PayPal","Stripe"), new Solution().topMerchantsByCount(merchants, 5));
    }

    @Test
    void emptyInput() {
        assertEquals(List.of(), new Solution().topMerchantsByCount(new String[]{}, 2));
    }

    @Test
    void singleMerchant() {
        String[] merchants = {"Netflix","Netflix","Netflix"};
        assertEquals(List.of("Netflix"), new Solution().topMerchantsByCount(merchants, 1));
    }

    @Test
    void twoWayTieTopOne() {
        // Zara=5, Apple=5; tiebreak lex: Apple < Zara => top-1: [Apple]
        String[] merchants = {"Zara","Zara","Zara","Zara","Zara","Apple","Apple","Apple","Apple","Apple"};
        assertEquals(List.of("Apple"), new Solution().topMerchantsByCount(merchants, 1));
    }
}
